import UIKit

class BankingAppModule {
    let accountBalance: Double
    var transactions = [Transaction]()
    
    init(accountBalance: Double) {
        self.accountBalance = accountBalance
    }
    
    func processTransaction(amount: Double, type: TransactionType) -> Bool {
        let newBalance = accountBalance + amount
        
        if newBalance < 0 {
            return false
        }
        
        transactions.append(Transaction(amount: amount, type: type))
        accountBalance = newBalance
        
        return true
    }
    
    func getAccountBalance() -> Double {
        return accountBalance
    }
}

class Transaction {
    let amount: Double
    let type: TransactionType
    
    init(amount: Double, type: TransactionType) {
        self.amount = amount
        self.type = type
    }
}

enum TransactionType {
    case deposit
    case withdrawal
}